 44	    LOG_E(PDCP, "%s:%d:%s: out of memory\n", __FILE__, __LINE__, __FUNCTION__);
 45	    exit(1);
 46	  }
 47	
 48	  pthread_mutexattr_t Attr;
 49	  pthread_mutexattr_init(&Attr);
 50	  // We need to be recursive because pdcp locks before forwarding, and calls in same thread,
 51	  // so, if same thread wants to send something back, and there is no itti intermediate thread, we deadlock on ourselves
 52	  pthread_mutexattr_settype(&Attr, PTHREAD_MUTEX_RECURSIVE);
 53	  if (pthread_mutex_init(&ret->lock, &Attr))
 54	    abort();
 55	  ret->enb_flag = enb_flag;
 56	
 57	  return ret;
 58	}
